/**
 * BSA §5324 anti-structuring gate (31 USC §5324; 31 CFR §1020.320).
 *
 * Scenario #19 of guides/use-cases.md: 3× USD 9,500 transactions inside
 * 24h is the classic sub-CTR structuring pattern that triggers
 * SAR-eligible REVIEW. The corpus models the verdict as BLOCK with
 * rejected_rule='ctr_structuring' since the platform's Transaction
 * status enum has no `:review` state today — the rule still fires on
 * the right pattern, and the verdict surface can be relaxed to REVIEW
 * once Transaction gains that state.
 *
 * Reads `account_holder.recent_debits_24h[]` (synthesised by
 * AtomicFi.RuleEngine.Payload.from_transaction/2 via
 * TransactionContext.list_recent_debits_for_account_holder/2).
 * Counts prior debits in the sub-CTR band (USD 5,000–9,999) — the
 * exact signature §5324 targets. Transactions above $10,000 are CTR-
 * reportable (filed but not blocked); transactions below $5,000 don't
 * look like structuring. If two or more prior sub-CTR debits exist
 * within the 24h window, the third+ debit in that band is blocked.
 */
export const handler = async (input) => {
  const debtor = input.debtor_payment_account;
  if (!debtor) return { ledger_accounts: {} };

  const SUB_CTR_MIN = 5000;
  const SUB_CTR_MAX = 9999;

  const txAmount = input.transaction && input.transaction.amount;
  if (typeof txAmount !== 'number' || txAmount < SUB_CTR_MIN || txAmount > SUB_CTR_MAX) {
    return { ledger_accounts: {} };
  }

  const ah = input.account_holder;
  const prior = (ah && ah.recent_debits_24h) || [];
  const subCtrCount = prior.filter(function (t) {
    return (t.amount || 0) >= SUB_CTR_MIN && (t.amount || 0) <= SUB_CTR_MAX;
  }).length;

  if (subCtrCount < 2) return { ledger_accounts: {} };

  const las = debtor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'ctr_structuring',
      block_reason: 'ctr_structuring',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
